export type GlossaryStatus = "draft" | "review" | "published" | "archived";
export type GlossaryAudience = "patient" | "dentist" | "student" | "developer" | "business-owner" | "manager" | "driver" | "operator" | "admin" | "ai-system" | string;
export type GlossaryEntry = {
    id: string;
    term: string;
    slug: string;
    definition: string;
    shortDefinition?: string;
    longDefinition?: string;
    language: string;
    audience: GlossaryAudience;
    status: GlossaryStatus;
    entityId?: string;
    missingEntityReason?: string;
    aliases?: string[];
    synonyms?: string[];
    examples?: string[];
    relatedObjectIds?: string[];
    relatedEntityIds?: string[];
    relatedCollectionIds?: string[];
    citations?: string[];
    media?: string[];
    canonicalUrl?: string;
    author?: string;
    reviewer?: string;
    reviewedAt?: string;
    createdAt: string;
    updatedAt: string;
    publishedAt?: string;
    archivedAt?: string;
};
